      lines.push(`  ];`);
      lines.push(`  return pks.join('${Utils.PK_SEPARATOR}');`);
    } else {
      const pk = meta.primaryKeys[0];
      const prop = meta.properties[pk];

      if (prop.kind !== ReferenceKind.SCALAR) {
